const body = $json.body || $json;
const evt = body.event;
const actor = body.actor || {};
const actorName = actor.name || 'Jemand';
const teamChannel = $env.SLACK_NOTIFY_CHANNEL || 'C0A7LTX603Z';
const appUrl = body.app_url || 'https://ludwig-a11y.github.io/halleluja-os/';
const openLink = `<${appUrl}|App öffnen>`;

let targets = [];

switch(evt) {
  case 'aufgabe_zugewiesen': {
    const msg = `📋 *${actorName}* hat dir eine Aufgabe zugewiesen:\n> ${body.aufgabe || '?'}${body.prio ? ' (' + body.prio + ')' : ''}${body.dl ? ' — fällig: ' + body.dl : ''}\n${openLink}`;
    if (body.fuer && body.fuer.slack_id) {
      targets.push({ channel: body.fuer.slack_id, text: msg });
    } else {
      targets.push({ channel: teamChannel, text: `📋 *${actorName}* → *${(body.fuer && body.fuer.name) || '?'}*: ${body.aufgabe || '?'}${body.prio ? ' (' + body.prio + ')' : ''} ${openLink}` });
    }
    break;
  }
  case 'meilenstein_erledigt': {
    targets.push({ channel: teamChannel, text: `🎯 *${actorName}* hat einen Meilenstein erreicht! 🎉\n> ✅ *${body.meilenstein || '?'}*${body.ziel ? '\n> Ziel: ' + body.ziel : ''}\n${openLink}` });
    break;
  }
  case 'big3_erledigt': {
    targets.push({ channel: teamChannel, text: `✅ *${actorName}* hat ein Big-3-Ziel erledigt (KW ${body.kw || '?'}):\n> ${body.big3 || '?'}` });
    break;
  }
  case 'blocker': {
    const msg = `⚠️ *${actorName}* meldet einen Blocker:\n> ${body.blocker || '?'}\n${openLink}`;
    const gfIds = body.gf_slack_ids || [];
    if (gfIds.length) {
      gfIds.forEach(sid => targets.push({ channel: sid, text: msg }));
    } else {
      targets.push({ channel: teamChannel, text: msg });
    }
    break;
  }
  default:
    targets.push({ channel: teamChannel, text: `${actorName}: ${evt}` });
}

return targets.map(t => ({ json: t }));
